+
+        // Same canonical path on two lookups -> same Arc.
+        let l1 = GitRepoLocks::global().lock_for(&canonical);
+        let l2 = GitRepoLocks::global().lock_for(&canonical);
+        assert!(Arc::ptr_eq(&l1, &l2));
+    }
